// HELPER: Calculation of compatibility score
function calculateBaseCompatibility(userA: UserProfile, userB: UserProfile): number {
  let score = 50; // base score if nothing matches
  
  // Mutual interests overlap
  const shared = userA.interests.filter(i => userB.interests.includes(i));
  score += shared.length * 8;

  // Goals overlap
  if (userA.relationship_goal === userB.relationship_goal) {
    score += 15;
  } else if (
    (userA.relationship_goal.includes('Long-term') || userA.relationship_goal.includes('Marriage')) &&
    (userB.relationship_goal.includes('Long-term') || userB.relationship_goal.includes('Marriage'))
  ) {
    score += 10;
  }

  // Habits/Lifestyle
  const valuesA = userA.relationship_values || [];
  const valuesB = userB.relationship_values || [];
  const sharedValues = valuesA.filter(v => valuesB.includes(v));
  score += sharedValues.length * 6;

  // Normalize between 40 and 99
  return Math.min(99, Math.max(45, score));
}

